import SwiftUI

struct CountRateLabelView: View {
    let value: Float?

    var body: some View {
        label { value, unit in
            RadiationLabelDefaultLayout(valueString: value, unitString: unit)
        }
    }

    func label<Content: View>(
        @ViewBuilder _ build: @escaping (_ value: String, _ unit: String) -> Content
    ) -> some View {
        _CountRateLabelContent(value: value, build: build)
    }
}

private struct _CountRateLabelContent<Content: View>: View {

    @Environment(\.radiationTrimZeros) private var trimZeros

    @AppStorage("countRateUnit") private var unit: Settings.CountRateMeasurementUnit = .cps

    let value: Float?
    let build: (String, String) -> Content

    var body: some View {
        let formatted = CountRateFormatted(rawValue: value, unit: unit)
        build(formatted.value.formattedValue(trimZeroes: trimZeros), String(localized: formatted.unit))
    }
}
```

