import SwiftUI

struct DoseLabelView: View {
    let value: Float?

    var body: some View {
        label { value, unit in
            RadiationLabelDefaultLayout(valueString: value, unitString: unit)
        }
    }

    func label<Content: View>(
        @ViewBuilder _ build: @escaping (_ value: String, _ unit: String) -> Content
    ) -> some View {
        _DoseLabelContent(value: value, mode: .dose, build: build)
    }
}

struct DoseRateLabelView: View {
    let value: Float?
    var rate: DoseDisplayMode.DoseRateSuffix = .hour

    var body: some View {
        label { value, unit in
            RadiationLabelDefaultLayout(valueString: value, unitString: unit)
        }
    }

    func label<Content: View>(
        @ViewBuilder _ build: @escaping (_ value: String, _ unit: String) -> Content
    ) -> some View {
        _DoseLabelContent(value: value, mode: .rate(rate), build: build)
    }
}

private struct _DoseLabelContent<Content: View>: View {

    @Environment(\.radiationTrimZeros) private var trimZeros

    @AppStorage("doseUnit") private var unit: Settings.DoseMeasurementUnit = .sievert

    let value: Float?
    let mode: DoseDisplayMode
    let build: (String, String) -> Content

    var body: some View {
        let formatted = DoseFormatted(rawValue: value, unit: unit, mode: mode)
        build(formatted.value.formattedValue(trimZeroes: trimZeros), formatted.unitString)
    }
}
```

**Note:** DoseRateLabelView is not a separate file but is defined as a struct within the DoseLabelView.swift file, alongside the DoseLabelView struct.
